// nextPriority returns the suggested priority for the next new rule:
// last rule's priority + 1, or 0 when the list is empty.
// Rules are already sorted (priority ASC, id ASC) so the last element
// always carries the highest priority number.
func nextPriority(rules []RuleRowData) int {
	if len(rules) == 0 {
		return 0
	}
	return rules[len(rules)-1].Priority + 1
}

